namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="settings-sidebar-title">Settings</h5>
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item">
                <button class="settings-nav-link @(section.Key == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="settings-nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="avatar-preview mb-3">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
            <div class="text-muted small mt-1">@_avatarUrl</div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">
                Discard Changes
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = DismissMessageAsync();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _successMessage = null;
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notification Preferences</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading preferences…</p>
    }
    else
    {
        <div class="mb-4">
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _successMessage = "Preferences saved!";
        _ = DismissMessageAsync();
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => _expanded = !_expanded">
        <span>Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">@_errorMessage</div>
            }
            @if (_successMessage is not null)
            {
                <div class="alert alert-success" role="alert">@_successMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _errorMessage;
    private string? _successMessage;

    private async Task UpdatePasswordAsync()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _errorMessage = "Please fill in all password fields.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _successMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services

@if (Session is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirmed { get; set; }
    [Parameter] public EventCallback OnCancelled { get; set; }

    private async Task Confirm() => await OnConfirmed.InvokeAsync();
    private async Task Cancel() => await OnCancelled.InvokeAsync();
}

@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled" @onchange="Toggle2FA" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy 'at' h:mm tt")
                    </p>
                }
            </div>
        </div>

        <div class="card">
            <div class="card-header">Active Sessions</div>
            <div class="card-body p-0">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            var isCurrent = session == _sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Session="@_sessionToRevoke"
                             OnConfirmed="ConfirmRevokeAsync"
                             OnCancelled="CancelRevoke" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)e.Value!;
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

