{"path": "/tmp/sv-0ce3a3894d954860a7bedb1ea7d31c0f/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled" @onchange="Toggle2FA" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy 'at' h:mm tt")
                    </p>
                }
            </div>
        </div>

        <div class="card">
            <div class="card-header">Active Sessions</div>
            <div class="card-body p-0">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            var isCurrent = session == _sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Session="@_sessionToRevoke"
                             OnConfirmed="ConfirmRevokeAsync"
                             OnCancelled="CancelRevoke" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)e.Value!;
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-0ce3a3894d954860a7bedb1ea7d31c0f/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="mb-4">
            <h5>Theme</h5>
            @foreach (var theme in _themes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme.ToLower()}")"
                           value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <h5>Font Size</h5>
            @foreach (var size in _fontSizes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size.ToLower()}")"
                           value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <label class="form-label"><h5 class="d-inline">Language</h5></label>
            <select class="form-select" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang.Key">@lang.Value</option>
                }
            </select>
        </div>

        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-header">Live Preview</div>
            <div class="card-body appearance-preview @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                <h5 style="font-size: 1.15em;">Sample Heading</h5>
                <p class="@(_compactMode ? "mb-1" : "mb-3")">
                    This is a preview of your selected appearance settings.
                    The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                    and language is <strong>@_languages.GetValueOrDefault(_language, _language)</strong>.
                </p>
                <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
    }
</div>

@code {
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Spanish",
        ["fr"] = "French",
        ["de"] = "German",
        ["ja"] = "Japanese",
        ["zh"] = "Chinese"
    };

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewButtonClass => _theme == "Dark" ? "btn-light" : "btn-primary";

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _successMessage = "Appearance settings saved!";
        _ = DismissMessageAsync();
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
"}

