@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@using sv_0ce3a3894d954860a7bedb1ea7d31c0f.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="mb-4">
            <h5>Theme</h5>
            @foreach (var theme in _themes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme.ToLower()}")"
                           value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme.ToLower()}")">@theme</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <h5>Font Size</h5>
            @foreach (var size in _fontSizes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size.ToLower()}")"
                           value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size.ToLower()}")">@size</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <label class="form-label"><h5 class="d-inline">Language</h5></label>
            <select class="form-select" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang.Key">@lang.Value</option>
                }
            </select>
        </div>

        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-header">Live Preview</div>
            <div class="card-body appearance-preview @PreviewThemeClass" style="font-size: @PreviewFontSize;">
                <h5 style="font-size: 1.15em;">Sample Heading</h5>
                <p class="@(_compactMode ? "mb-1" : "mb-3")">
                    This is a preview of your selected appearance settings.
                    The theme is <strong>@_theme</strong>, font size is <strong>@_fontSize</strong>,
                    and language is <strong>@_languages.GetValueOrDefault(_language, _language)</strong>.
                </p>
                <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">@_successMessage</div>
        }
    }
</div>

@code {
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Spanish",
        ["fr"] = "French",
        ["de"] = "German",
        ["ja"] = "Japanese",
        ["zh"] = "Chinese"
    };

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        "Light" => "preview-light",
        _ => "preview-system"
    };

    private string PreviewButtonClass => _theme == "Dark" ? "btn-light" : "btn-primary";

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        _successMessage = "Appearance settings saved!";
        _ = DismissMessageAsync();
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

