toolArgs.file_text:
@page "/settings"
@namespace sv_0ce3a3894d954860a7bedb1ea7d31c0f.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 600px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

::deep .settings-sidebar-title {
    font-weight: 600;
    margin-bottom: 1rem;
    padding: 0.5rem 0.75rem;
    color: #495057;
}

::deep .settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

::deep .settings-nav-item {
    margin-bottom: 2px;
}

::deep .settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: none;
    background: transparent;
    border-radius: 6px;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    text-align: left;
}

::deep .settings-nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

::deep .settings-nav-icon {
    font-size: 1.1rem;
}

::deep .settings-section h3 {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .avatar-preview {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
}

::deep .avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
    background-color: #f8f9fa;
}

::deep .appearance-preview {
    border-radius: 6px;
    padding: 1.25rem;
    transition: all 0.2s;
}

::deep .preview-light {
    background-color: #ffffff;
    color: #212529;
    border: 1px solid #dee2e6;
}

::deep .preview-dark {
    background-color: #1e1e2e;
    color: #e0e0e0;
    border: 1px solid #444;
}

::deep .preview-system {
    background-color: #f8f9fa;
    color: #212529;
    border: 1px solid #dee2e6;
}

::deep .fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.5);
    z-index: 1040;
}

::deep .modal.d-block {
    z-index: 1050;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

